import{_ as t,o as e,c as l,R as a,k as i}from"./chunks/framework.RKjL2WU4.js";const q=JSON.parse('{"title":"Git 教程","description":"","frontmatter":{},"headers":[],"relativePath":"guild/git.md","filePath":"guild/git.md"}'),s={name:"guild/git.md"},r=a('<h1 id="git-教程" tabindex="-1">Git 教程 <a class="header-anchor" href="#git-教程" aria-label="Permalink to &quot;Git 教程&quot;">​</a></h1><h2 id="git-文档" tabindex="-1">Git 文档 <a class="header-anchor" href="#git-文档" aria-label="Permalink to &quot;Git 文档&quot;">​</a></h2><p><a href="https://git-scm.com/docs" target="_blank" rel="noreferrer">官方文档</a></p><h2 id="git-branch" tabindex="-1">git branch <a class="header-anchor" href="#git-branch" aria-label="Permalink to &quot;git branch&quot;">​</a></h2><ul><li>git branch 查看本地分支</li><li>git branch -r 查看远程分支</li><li>git branch -a 查看本地&amp;远程分支</li><li>git branch -d xxx 删除本地分支</li><li>git branch -r | grep main 查看远程的包含 main 的分支</li><li>git branch | grep main | xargs git branch -D 批量删除本地分支</li><li>git branch -a | grep -v -E &#39;master|develop&#39; | xargs git branch -D // 只保留 master 等分支</li><li>git branch -r | grep -v -E &#39;master|develop&#39; | sed &#39;s/origin///g&#39; | xargs -I {} git push origin :{}</li><li>git branch -r | grep &#39;main&#39; | xargs -I {} basename {} | xargs -I {} git push origin :{} // 批量删除远程分支</li><li>git remote prune origin // 刷新一下分支列表</li></ul><h2 id="git-checkout" tabindex="-1">git checkout <a class="header-anchor" href="#git-checkout" aria-label="Permalink to &quot;git checkout&quot;">​</a></h2><ul><li>git checkout xxx 切换到某个分支</li><li>git checkout . 放弃本次修改</li><li>git checkout -b xxx origin/xxx 创建一个和远程分支关联的分支</li><li>git checkout -b xxx 创建一个新分支</li></ul><h2 id="git-merge" tabindex="-1">git merge <a class="header-anchor" href="#git-merge" aria-label="Permalink to &quot;git merge&quot;">​</a></h2><ul><li>git merge branchName 将 branchName 分支的更改合并到当前分支</li><li>git merge --abort 取消上一次合并</li></ul><h2 id="git-clone" tabindex="-1">git clone <a class="header-anchor" href="#git-clone" aria-label="Permalink to &quot;git clone&quot;">​</a></h2><ul><li>git clone repositoryUrl 克隆远程仓库到当前目录</li><li>git clone -b branchName repositoryUr 克隆指定分支</li></ul><h2 id="git-pull" tabindex="-1">git pull <a class="header-anchor" href="#git-pull" aria-label="Permalink to &quot;git pull&quot;">​</a></h2><ul><li>git pull origin branchName 将远程分支拉取到本地当前分支</li><li>git pull origin branchName --force 强制将远程分支拉取到本地当前分支</li><li>git pull --rebase origin branchName 将远程分支拉取到本地分支，并在本地分支上执行 rebase 操作</li></ul><h2 id="git-add" tabindex="-1">git add <a class="header-anchor" href="#git-add" aria-label="Permalink to &quot;git add&quot;">​</a></h2><ul><li>git add . 将所有修改添加到暂存区</li><li>git add fileName 将指定文件添加到暂存区</li></ul><h2 id="git-commit" tabindex="-1">git commit <a class="header-anchor" href="#git-commit" aria-label="Permalink to &quot;git commit&quot;">​</a></h2><ul><li>git commit -m &quot;Commit message&quot; 将提交暂存区的所有更改附带一条信息进行提交</li></ul><h2 id="git-remote" tabindex="-1">git remote <a class="header-anchor" href="#git-remote" aria-label="Permalink to &quot;git remote&quot;">​</a></h2><ul><li>git remote add origin repositoryUrl 关联远程仓库</li></ul><h2 id="git-push" tabindex="-1">git push <a class="header-anchor" href="#git-push" aria-label="Permalink to &quot;git push&quot;">​</a></h2><ul><li>git push origin branchName 将本地分支推送到远程分支</li><li>git push -u origin branchName 将本地分支推送到远程仓库，并将远程分支设置为相同名称</li><li>git push -f origin branchName 强制推送到远程仓库，即使有冲突</li><li>git push origin --delete branchName 删除远程分支</li></ul><h2 id="git-tag" tabindex="-1">git tag <a class="header-anchor" href="#git-tag" aria-label="Permalink to &quot;git tag&quot;">​</a></h2><ul><li>git tag -a tagName -m &#39;标签的说明&#39; // -a annotated</li><li>git push origin tagName // 推送到远程</li></ul><h2 id="git-log" tabindex="-1">git log <a class="header-anchor" href="#git-log" aria-label="Permalink to &quot;git log&quot;">​</a></h2><ul><li>git log --author=alan // 过滤作者名称 --oneline // 每条记录只显示一行</li></ul><h2 id="git-stash" tabindex="-1">git stash <a class="header-anchor" href="#git-stash" aria-label="Permalink to &quot;git stash&quot;">​</a></h2>',26),o=i("ul",null,[i("li",{name:""},"git stash save"),i("li",null,"git stash list"),i("li",null,"git stash pop"),i("li",{index:""},"git stash apply"),i("li",{index:""},"git stash drop")],-1),n=a(`<h2 id="git-reset" tabindex="-1">git reset <a class="header-anchor" href="#git-reset" aria-label="Permalink to &quot;git reset&quot;">​</a></h2><ul><li>git reset --soft HEAD~1 撤销上一次的提交</li></ul><h2 id="git-cherry-pick" tabindex="-1">git cherry-pick <a class="header-anchor" href="#git-cherry-pick" aria-label="Permalink to &quot;git cherry-pick&quot;">​</a></h2><ul><li>git cherry-pick commitId1 commitId2 将其他分支的 commit 摘取过来</li></ul><h2 id="gitignore" tabindex="-1">.gitignore <a class="header-anchor" href="#gitignore" aria-label="Permalink to &quot;.gitignore&quot;">​</a></h2><ul><li>以斜杠“/”开头表示目录</li><li>以星号“*”通配多个字符</li><li>以问号“?”通配单个字符</li><li>以方括号“[]”包含单个字符的匹配列表</li><li>以叹号“!”表示不忽略(跟踪)匹配到的文件或目录</li><li>git 对于 .ignore 配置文件是按行从上到下进行规则匹配的，意味着如果前面的规则匹配的范围更大，则后面的规则将不会生效</li><li>只能作用于 Untracked Files，也就是那些从来没有被 Git 记录过的文件（自添加以后，从未 add 及 commit 过的文件）</li></ul><h2 id="review-pr" tabindex="-1">review pr <a class="header-anchor" href="#review-pr" aria-label="Permalink to &quot;review pr&quot;">​</a></h2><p>如果是简单的功能我们可以直接通过 PR 地址进行 review，对于复杂一些的功能，我们应该在本地对功能进行验证。此时可以使用 Git 命令将当前 PR 拉到本地进行验证。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>git fetch origin pull/{id}/head:{branchname}</span></span></code></pre></div><ul><li>id: PR 的 id</li><li>branchname: 你本地创建的新分支的名称</li></ul><h2 id="git-提交规范" tabindex="-1">Git 提交规范 <a class="header-anchor" href="#git-提交规范" aria-label="Permalink to &quot;Git 提交规范&quot;">​</a></h2><p>良好的 Git 提交日志非常重要，最明显的一点是，它让整个 Git 提交历史的阅读变得非常轻松。 一眼看上去，就知道每个提交是做了什么，是加了新功能，还是修改了 bug，是维护了文档，还是调整了单元测试，都一目了然。</p><p>每个提交的标题是强制的，又具有特殊格式，包括修改类型、影响范围和内容主题。 每个类型值都表示了不同的含义，类型值必须是以下的其中一个：</p><ul><li>feat：提交新功能</li><li>fix：修复了 bug</li><li>docs：只修改了文档</li><li>style：调整代码格式，未修改代码逻辑（比如修改空格、格式化、缺少分号等）</li><li>refactor：代码重构，既没修复 bug 也没有添加新功能</li><li>perf：性能优化，提高性能的代码更改</li><li>test：添加或修改代码测试</li><li>chore：对构建流程或辅助工具和依赖库（如文档生成等）的更改</li><li>revert：回滚某个提交</li></ul><p>标题是对提交的最直接最简明的说明，然后在提交的正文中对标题的内容进行补充，说明对提交的详细描述。正文中可以包含：</p><ul><li>详细描述本次提交的变更范围</li><li>为什么提交这次变更，有相关的需求或 issue，可关联相应链接</li><li>有其他关联的 pr 可关联相应链接</li><li>对于界面样式或交互的修改，可附上截图</li><li>对于文档、测试例等关联的修改，可添加勾选项帮助确认同步修改</li></ul><h2 id="macos-上配置-ssh-key" tabindex="-1">Macos 上配置 SSH key <a class="header-anchor" href="#macos-上配置-ssh-key" aria-label="Permalink to &quot;Macos 上配置 SSH key&quot;">​</a></h2><ol><li>检查是否已经有 ssh</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>ls -al ~/.ssh</span></span></code></pre></div><p>如果已经有 SSH 可以看到类似 id_rsa 等文件</p><ol start="2"><li>如果没有 SSH key，可以执行以下命令生成</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>ssh-keygen -t rsa -b 4096 -C &quot;&lt;your_email&gt;&quot;</span></span></code></pre></div><ol start="3"><li>添加 SSH 到 SSH Agent</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>eval &quot;$(ssh-agent -s)&quot;</span></span>
<span class="line"><span>ssh-add ~/.ssh/id_rsa</span></span></code></pre></div><ol start="4"><li>复制 SSH</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>pbcopy &lt; ~/.ssh/id_rsa.pub</span></span></code></pre></div><ol start="5"><li>添加 SSH 到 GitHub</li></ol><p>在 GitHub 的个人设置页面，点击 SSH and GPG keys，然后点击 New SSH key，将刚才复制的 SSH key 粘贴进去，并命名。</p><ol start="6"><li>测试连接</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>ssh -T git@github.com</span></span></code></pre></div><blockquote><p>我使用的 git 版本管理工具是 Fork，可以 New SSH key 填写 key file name 和 emil 后生成一个新的 SSH key，然后将这个 key 复制到 GitHub 的 SSH key 里。</p></blockquote>`,31),h=[r,o,n];function g(c,d,u,p,b,m){return e(),l("div",null,h)}const _=t(s,[["render",g]]);export{q as __pageData,_ as default};
